B.a9T=new A.aP("Neyin do\u011fru neyin yanl\u0131\u015f oldu\u011funu hisseden, kusursuzu hayal eden, yanl\u0131\u015f olan \u015fey d\xfczeltilene kadar dinlenmeden \xe7abalayan bir yap\u0131ya sahibim.")
B.a9l=new A.aP("Duygusal, ili\u015fkilerini \xe7ok \xf6nemseyen, sevgiye \xe7ok de\u011fer veren, cana yak\u0131n, yard\u0131msever, \xe7abuk ve kolay ileti\u015fim kurabilen bir yap\u0131ya sahibim.")
B.a9L=new A.aP("Ba\u015far\u0131l\u0131 ve etkileyici olmaktan ho\u015flanan, stat\xfc ve g\xf6r\xfcn\xfcm\xfc \xf6nemseyen, h\u0131rsl\u0131, enerjik ve rekabet\xe7i bir yap\u0131ya sahibim.")
B.a9v=new A.aP("Hassas, empati kurmay\u0131 \xf6nemseyen, \xf6zg\xfcnl\xfc\u011fe ve bireyselli\u011fe \xe7ok \xf6nem veren, ya\u015fad\u0131klar\u0131 ve hissettikleri \xfczerinde derinlemesine d\xfc\u015f\xfcnen bir yap\u0131ya sahibim.")
B.a9K=new A.aP("Bilgiye ve ara\u015ft\u0131rmaya merakl\u0131, yaln\u0131z kalmaktan rahats\u0131z olmayan, kendini ve olaylar\u0131 duygulardan ba\u011f\u0131ms\u0131z olarak g\xf6zlemleyip rasyonel ve nesnel analiz yapmaya e\u011filimli bir yap\u0131ya sahibim.")
B.aa0=new A.aP("G\xfcven ve emniyet i\xe7inde hissetmeyi \xe7ok \xf6nemseyen, tedbirli, merakl\u0131, sorgulay\u0131c\u0131, riskleri hesaplayabilen ve her zaman B plan\u0131 bulunduran bir yap\u0131ya sahibim.")
B.a9Q=new A.aP("Ke\u015ffetmeyi ve yeni \u015feyler deneyimlemeyi seven, mant\u0131\u011f\u0131yla hareket eden, duygulara tak\u0131lmayan, iyimser, merakl\u0131, d\u0131\u015fa d\xf6n\xfck, ne\u015feli, konu\u015fkan ve giri\u015fken bir yap\u0131ya sahibim.")
B.a9Z=new A.aP("Cesur, kararl\u0131, otoriter, insanlar\u0131 etkilemeyi seven, g\xfc\xe7l\xfc ve ba\u011f\u0131ms\u0131z olmay\u0131 \xf6nemseyen, risk almaktan \xe7ekinmeyen, zorluklara kar\u015f\u0131 dayan\u0131kl\u0131, m\xfccadeleden ve \xe7at\u0131\u015fmadan ka\xe7\u0131nmayan bir yap\u0131ya sahibim.")
B.a9G=new A.aP("Huzuru arayan, sab\u0131rl\u0131, sakin, gerilimden ka\xe7\u0131nan, sosyal ortamlarda g\xf6rmezden gelinmekten ho\u015flanmayan ancak \xf6ne \xe7\u0131kmay\u0131 da pek tercih etmeyen bir yap\u0131ya sahibim.")
B.a_4=s([B.a9T,B.a9l,B.a9L,B.a9v,B.a9K,B.aa0,B.a9Q,B.a9Z,B.a9G],t.DC)
