B.aa8=new A.aP("Kendimle vakit ge\xe7irmenin keyfini \xe7\u0131kart\u0131r\u0131m.")
B.a9j=new A.aP("Duygulara kar\u015f\u0131 ilgim ve alakam artar.")
B.aa3=new A.aP("Ya\u015fam\u0131mda kendimle ilgili rutinlerin say\u0131s\u0131 artar.")
B.a9k=new A.aP("Anlatt\u0131\u011f\u0131m konularda daha iddial\u0131 olurum.")
